// Normalize the error payload n8n hands to an Error Trigger into a flat
// dead-letter row. Captures the failed node, message, and original lead data
// when available.
const e = $json;
const exec = e.execution || {};
const lastNode = (exec.lastNodeExecuted) || 'unknown';
const errMsg = (e.error && (e.error.message || e.error.description)) || exec.error?.message || 'unknown error';

// best-effort recovery of the original lead payload from the trigger data
let lead = {};
try {
  const triggerData = e.execution?.data?.resultData?.runData;
  // not always available; fall back to empty
} catch (_) {}

return [{
  json: {
    failed_at: new Date().toISOString(),
    workflow: e.workflow?.name || 'unknown',
    failed_node: lastNode,
    error_reason: String(errMsg).slice(0, 500),
    execution_id: exec.id || '',
    execution_url: exec.url || '',
    stage: 'runtime-error'
  }
}];
